114	          args = {
115	            taskType: 'INPAINTING',
116	            inPaintingParams,
117	            imageGenerationConfig,
118	          };
119	          break;
120	        }
121	
122	        case 'OUTPAINTING': {
123	          const outPaintingParams: Record<string, unknown> = {
124	            image: sourceImageBase64,
125	            ...(prompt ? { text: prompt } : {}),
126	            ...(providerOptions?.bedrock?.negativeText
127	              ? { negativeText: providerOptions.bedrock.negativeText }
128	              : {}),
129	            ...(providerOptions?.bedrock?.outPaintingMode
130	              ? { outPaintingMode: providerOptions.bedrock.outPaintingMode }
131	              : {}),
132	          };
133	
134	          // Outpainting requires a maskImage (white pixels = area to change)
135	          if (hasMask) {
