150	      headers: combineHeaders(
151	        await resolve(this.config.headers),
152	        headers,
153	        preferHeader,
154	      ),
155	
156	      body: {
157	        input: {
158	          prompt,
159	          aspect_ratio: aspectRatio,
160	          size,
161	          seed,
162	          num_outputs: n,
