import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonResponseHandler,
  createJsonErrorResponseHandler,
  postJsonToApi,
  lazySchema,
  parseProviderOptions,
  zodSchema,
  InferSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support aspect ratio. Use `size` instead.',
      });
    }

    // Parse and validate provider options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const style = pixelArtOptions?.style ?? undefined;
    const pixelDensity = pixelArtOptions?.pixelDensity ?? undefined;
    // Provider-specific size overrides the standard size option
    const finalSize = pixelArtOptions?.size ?? size;

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        model: this.modelId,
        n,
        ...(finalSize != null ? { size: finalSize } : {}),
        ...(seed != null ? { seed } : {}),
        ...(style != null ? { style } : {}),
        ...(pixelDensity != null ? { pixel_density: pixelDensity } : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: error => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
    });

    return {
      images: response.images.map(img => img.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// limited version of the schema, focused on what is needed for the implementation
// this approach limits breakages when the API changes and increases efficiency
const pixelArtResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      images: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The style of pixel art to generate.
       *
       * - `pixel`: Standard pixel art style.
       * - `retro`: Retro/vintage pixel art style.
       * - `8bit`: 8-bit era pixel art style.
       */
      style: z.enum(['pixel', 'retro', '8bit']).nullish(),

      /**
       * The pixel density of the generated image.
       * Must be between 1 and 64.
       */
      pixelDensity: z.number().min(1).max(64).nullish(),

      /**
       * Override the size of the generated image.
       * Takes precedence over the standard `size` option.
       */
      size: z.string().nullish(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

